claude-code.alternativeContent:
# Alternative: Manual JSON config
# ~/.config/claude/mcp.json
{
  "mcpServers": {
    "moira": {
      "type": "http",
      "url": "{{mcpUrl}}"
    }
  }
}

# Then: /mcp → Authenticate

vscode.alternativeContent:
# Install MCP extension:
# ext install mcp-connector

# Then in settings.json:
{
  "mcp.servers": {
    "moira": {
      "url": "{{mcpUrl}}",
      "transport": "http"
    }
  }
}

# Or: Command Palette → "MCP: Add Server"

zed.content:
# Zed editor:

# 1. Open Settings (⌘+,)
# 2. Add to settings.json under context_servers:
#
# "context_servers": {
#   "moira": {
#     "url": "{{mcpUrl}}"
#   }
# }
#
# 3. Restart Zed
# 4. Authenticate when prompted

gemini-cli.content:
# Gemini CLI:

# 1. Edit ~/.gemini/settings.json:
#
# "mcpServers": {
#   "moira": {
#     "httpUrl": "{{mcpUrl}}"
#   }
# }
#
# 2. Run: gemini auth
# 3. Complete OAuth flow

connect.code:
# Claude Code (CLI)
claude mcp add moira https://{host}/mcp

# Cursor / VS Code (settings.json)
{
  "mcpServers": {
    "moira": {
      "url": "https://{host}/mcp"
    }
  }
}

execute.code:
# Moira returns:
{
  "directive": "Implement the feature
    according to the approved plan",
  "completionCondition": "All tests pass,
    code follows project patterns",
  "inputSchema": { ... }
}

# Agent works → submits result
mcp__moira__step({
  processId: "abc-123",
  input: { ... }
})
